- (void)launchVApp:(WBVAppModel *)vapp {
    void (^launchBlock)(void) = ^{
        self.launchVC = WBGroMoreAdManager.sharedManager.vappLaunchVC;
        self.launchVC.progressView.duration = vapp.versionInfo.timeLaunch;
        self.launchVC.progressView.titleLabel.text = @"正在启动应用";
        self.launchVC.progressView.tipIndex = [self getCurrentLaunchTipIndex];
        self.launchVC.progressView.tips = [self getCurrentLaunchTips];
        self.launchVC.progressView.largeLogoView.animDur = vapp.versionInfo.timeLaunch;
        self.launchVC.progressView.largeLogoView.animType = WBProgressVappLaunchAnimTypeFadeIn;

        UIViewController *rootVc = [WBAppManager getUIApplicationRootViewController];
        [rootVc presentViewController:self.launchVC animated:NO completion:^{
            [[WBVAppManager sharedManager] launchVApp:vapp callback:nil];
        }];
    };

    if (_launchVC) {
        [_launchVC dismissViewControllerAnimated:NO completion:^{
            launchBlock();
        }];
    } else {
        launchBlock();
    }
}

