    launchVC = [[WBVappLaunchViewController alloc] init];
    launchVC.progressView.duration = vapp.versionInfo.timeLaunch;
    launchVC.progressView.titleLabel.text = @"正在启动应用";
    launchVC.progressView.tipIndex = [self getCurrentLaunchTipIndex];
    launchVC.progressView.tips = [self getCurrentLaunchTips];
    self.launchVC = launchVC;

    UIViewController *rootVc = [WBAppManager getUIApplicationRootViewController];
    [rootVc presentViewController:self.launchVC animated:NO completion:^{
        if (completionHandler) completionHandler();
    }];
}

